@ARTICLE{10.2147/IJN.S452194,
	author = {Lu J and Zeng Y and Zhong H and Guo W and Zhang Y and Mai W and Qin Y and Su X and Zhang B and Wu W and Zhu Y and Huang Q and Ye Y},
	title = {Dual-Stimuli-Responsive Gut Microbiota-Targeting Nitidine Chloride-CS/PT-NPs Improved Metabolic Status in NAFLD.},
	journal = {Int J Nanomedicine},
	year = {2024},
	abstract = {BACKGROUND AND PURPOSE: Nitidine chloride (NC) is a botanical drug renowned for its potent anti-inflammatory, antimalarial, and hepatocellular carcinoma-inhibiting properties; however, its limited solubility poses challenges to its development and application. To address this issue, we have devised a colon-targeted delivery system (NC-CS/PT-NPs) aimed at modulating the dysbiosis of the gut microbiota by augmenting the interaction between NC and the intestinal microbiota, thereby exerting an effect against nonalcoholic fatty liver disease. METHODS: The NC-CS/PT-NPs were synthesized using the ion gel method. Subsequently, the particle size distribution, morphology, drug loading efficiency, and release behavior of the NC-CS/PT-NPs were characterized. Furthermore, the impact of NC-CS/PT-NPs on non-alcoholic fatty liver disease (NAFLD) induced by a high-fat diet (HFD) in mice was investigated through serum biochemical analysis, ELISA, and histochemical staining. Additionally, the influence of NC-CS/PT-NPs on intestinal microbiota was analyzed using 16S rDNA gene sequencing. RESULTS: The nanoparticles prepared in this study have an average particle size of (255.9±5.10) nm, with an encapsulation rate of (72.83±2.13) % and a drug loading of (4.65±0.44) %. In vitro release experiments demonstrated that the cumulative release rate in the stomach and small intestine was lower than 22.0%, while it reached 66.75% in the colon. In vivo experiments conducted on HFD-induced NAFLD mice showed that treatment with NC-CS/PT-NPs inhibited weight gain, decreased serum aspartate aminotransferase (AST), Alanine aminotransferase (ALT) and lipid levels, improved liver and intestinal inflammation, and altered the diversity of gut microbiota in mice. CONCLUSION: This study provides new evidence for the treatment of NAFLD through the regulation of gut microbiota using active ingredients from traditional Chinese medicine.},
	doi = {10.2147/IJN.S452194},
	pmid = {38476281 [Indexed for MEDLINE]},
	note = {PMC10929648}
}

@ARTICLE{10.1016/j.jgr.2023.07.005,
	author = {Hu QR and Hong H and Zhang ZH and Feng H and Luo T and Li J and Deng ZY and Chen F},
	title = {Methods on improvements of the poor oral bioavailability of ginsenosides: Pre-processing, structural modification, drug combination, and micro- or nano- delivery system.},
	journal = {J Ginseng Res},
	year = {2023},
	abstract = {Panax ginseng Meyer is a traditional Chinese medicine that is widely used as tonic in Asia. The main pharmacologically active components of ginseng are the dammarane-type ginsenosides, which have been shown to have anti-cancer, anti-inflammatory, immunoregulatory, neuroprotective, and metabolic regulatory activities. Moreover, some of ginsenosides (eg, Rh2 and Rg3) have been developed into nutraceuticals. However, the utilization of ginsenosides in clinic is restrictive due to poor permeability in cells and low bioavailability in human body. Obviously, the dammarane skeleton and glycosyls of ginsenosides are responsible for these limitations. Therefore, improving the oral bioavailability of ginsenosides has become a pressing issue. Here, based on the structures of ginsenosides, we summarized the understanding of the factors affecting the oral bioavailability of ginsenosides, introduced the methods to enhance the oral bioavailability and proposed the future perspectives on improving the oral bioavailability of ginsenosides.},
	doi = {10.1016/j.jgr.2023.07.005},
	pmid = {38107396},
	note = {PMC10721471}
}

@ARTICLE{10.1016/j.biopha.2023.115511,
	author = {Feng JH and Chen K and Shen SY and Luo YF and Liu XH and Chen X and Gao W and Tong YR},
	title = {The composition, pharmacological effects, related mechanisms and drug delivery of alkaloids from Corydalis yanhusuo.},
	journal = {Biomed Pharmacother},
	year = {2023},
	abstract = {Corydalis yanhusuo W. T. Wang, also known as yanhusuo, yuanhu, yanhu and xuanhu, is one of the herb components of many Chinese Traditional Medicine prescriptions such as Jin Ling Zi San and Yuanhu-Zhitong priscription. C. yanhusuo was traditionally used to relieve pain and motivate blood and Qi circulation. Now there has been growing interest in pharmacological effects of alkaloids, the main bioactive components of C. yanhusuo. Eighty-four alkaloids isolated from C. yanhusuo are its important bioactive components and can be characterized into protoberberine alkaloids, aporphine alkaloids, opiate alkaloids and others and proper extraction or co-administration methods modulate their contents and efficacy. Alkaloids from C. yanhusuo have various pharmacological effects on the nervous system, cardiovascular system, cancer and others through multiple molecular mechanisms such as modulating neurotransmitters, ion channels, gut microbiota, HPA axis and signaling pathways and are potential treatments for many diseases. Plenty of novel drug delivery methods such as autologous red blood cells, self-microemulsifying drug delivery systems, nanoparticles and others have also been investigated to better exert the effects of alkaloids from C. yanhusuo. This review summarized the alkaloid components of C. yanhusuo, their pharmacological effects and mechanisms, and methods of drug delivery to lay a foundation for future investigations.},
	doi = {10.1016/j.biopha.2023.115511},
	pmid = {37729733 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.cytogfr.2023.08.005,
	author = {Huang J and Wang X and Wang Z and Deng L and Wang Y and Tang Y and Luo L and Leung EL},
	title = {Extracellular vesicles as a novel mediator of interkingdom communication.},
	journal = {Cytokine Growth Factor Rev},
	year = {2023},
	abstract = {Extracellular vesicles (EVs) are nanosized lipid bilayer-delimited particles secreted from almost all types of cells including bacteria, mammals and plants, and are presumed to be mediators of intercellular communication. Bacterial extracellular vesicles (BEVs) are nanoparticles with diverse diameters, ranging from 20 to 400 nm. BEVs are composed of soluble microbial metabolites, including nucleic acid, proteins, lipoglycans, and short-chain fatty acids (SCFAs). In addition, EVs may contain quorum sensing peptides that are endowed with the ability to protect bacteria against bacteriophages, form and maintain bacterial communities, and modulate the host immune system. BEVs are potentially promising therapeutic modalities for use in vaccine development, cancer immunotherapy regimens, and drug delivery cargos. Plant-derived EVs (PEVs), such as EVs derived from herbal medicines, can be absorbed by the gut microbiota and influence the composition and homeostasis of gut microbiota. This review highlights the roles of BEVs and PEVs in bacterial and plant physiology and discusses crosstalk among gut bacteria, host metabolism and herbal medicine. In summary, EVs represent crucial communication messengers in the gut microbiota, with potential therapeutic value in the delivery of herbal medicines.},
	doi = {10.1016/j.cytogfr.2023.08.005},
	pmid = {37634980 [Indexed for MEDLINE]}
}

@ARTICLE{10.1039/d2fo03824b,
	author = {Yang M, Abdullah and Ahmad N and Hussain M and Lu X and Xu J and Zhong H and Guan R},
	title = {A review of recent advances on cyanidin-3-glucoside: the biotransformation, absorption, bioactivity and applications of nano-encapsulation.},
	journal = {Food Funct},
	year = {2023},
	abstract = {Anthocyanins are a class of dietary polyphenols that exhibit technological and bioactive-relevant properties. C3G is absorbed in its unmodified molecular form in the upper digestive tract, goes through the extended first-passage metabolism and its metabolites enter the bloodstream. The C3G metabolites possess health benefits such as antioxidant, cardio-protective, anti-inflammatory, neuroprotective, anti-cancer, anti-diabetic, and anti-thrombotic activities. However, the efficacy and distribution of C3G in the human body are restricted due to its low stability and bioaccessibility. Inspiringly, the lipid-, polysaccharide-, protein-, and nanocapsule-associated conjugates have achieved targeted delivery with enhanced bioaccessibility and controlled release. In this review, the absorption and transportation modes, decomposition and metabolism processes, functional activity mechanisms, and improved methods for enhancing the bioavailability of C3G are summarized. Moreover, the aspects of the gut microbiota regulation, C3G-mediated cytoprotection and different biocompatible materials applications are briefly discussed.},
	doi = {10.1039/d2fo03824b},
	pmid = {37403833 [Indexed for MEDLINE]}
}

@ARTICLE{10.1126/sciadv.adf3887,
	author = {He H and Qin Q and Xu F and Chen Y and Rao S and Wang C and Jiang X and Lu X and Xie C},
	title = {Oral polyphenol-armored nanomedicine for targeted modulation of gut microbiota-brain interactions in colitis.},
	abstract = {Developing oral nanomedicines that suppress intestinal inflammation while modulating gut microbiota and brain interactions is essential for effectively treating inflammatory bowel disease. Here, we report an oral polyphenol-armored nanomedicine based on tumor necrosis factor-α (TNF-α)-small interfering RNA and gallic acid-mediated graphene quantum dot (GAGQD)-encapsulated bovine serum albumin nanoparticle, with a chitosan and tannin acid (CHI/TA) multilayer. Referred to "armor," the CHI/TA multilayer resists the harsh environment of the gastrointestinal tract and adheres to inflamed colon sites in a targeted manner. TA provides antioxidative stress and prebiotic activities that modulate the diverse gut microbiota. Moreover, GAGQD protected TNF-α-siRNA delivery. Unexpectedly, the armored nanomedicine suppressed hyperactive immune responses and modulated bacterial gut microbiota homeostasis in a mouse model of acute colitis. Notably, the armored nanomedicine alleviated anxiety- and depression-like behaviors and cognitive impairment in mice with colitis. This armor strategy sheds light on the effect of oral nanomedicines on bacterial gut microbiome-brain interactions.},
	doi = {10.1126/sciadv.adf3887},
	pmid = {37235662 [Indexed for MEDLINE]},
	note = {PMC10219598}
}

@ARTICLE{10.1002/advs.202206957,
	author = {Yu J and Guo Z and Yan J and Bu C and Peng C and Li C and Mao R and Zhang J and Wang Z and Chen S and Yao M and Xie Z and Yang C and Yang YY and Yuan P and Ding X},
	title = {Gastric Acid-Responsive ROS Nanogenerators for Effective Treatment of Helicobacter pylori Infection without Disrupting Homeostasis of Intestinal Flora.},
	journal = {Adv Sci (Weinh)},
	year = {2023},
	abstract = {Helicobacter pylori (H. pylori) has infected more than half of the world's population, and is the major cause of gastric cancer. The efficacy of standard antibiotic-based triple therapy is declining due to drug resistance development. Herein, a pH-responsive reactive oxygen species (ROS) nanogenerator (Fe-HMME@DHA@MPN) composed of acid-responsive metal polyphenol network (MPN) shell and mesoporous metal-organic nanostructure core [Fe-HMME (hematoporphyrin monomethyl ether, sonosensitizer)] loaded with dihydroartemisinin (DHA) is reported. These nanoparticles generate more ROS singlet oxygen than sonosensitizer HMME under ultrasonication, and this sonodynamic process is fueled by oxygen generated through Fenton/Fenton-like reactions of the degraded product in gastric acid Fe (II) and hydrogen peroxide (H2 O2 ) in the infection microenvironment. The encapsulated DHA, as a hydroperoxide source, is found to enhance the peroxidase-like activity of the Fe-HMME@DHA@MPN to generate ROS hydroxyl radical, beneficial for the microenvironment without sufficient H2 O2 . In vitro experiments demonstrate that the ROS nanogenerators are capable of killing multidrug-resistant H. pylori and removing biofilm, and ROS nanogenerators show high therapeutic efficacy in a H. pylori infection mouse model. Unlike the triple therapy, the nanogenerators display negligible side effects toward the normal gut microbiota. Taken together, these self-enhanced ROS nanogenerators have a great potential for treatment of H. pylori infection.},
	doi = {10.1002/advs.202206957},
	pmid = {37127895 [Indexed for MEDLINE]},
	note = {PMC10369278}
}

@ARTICLE{10.1007/s00204-022-03391-2,
	author = {Vivarelli S and Costa C and Teodoro M, Giambò F and Tsatsakis AM and Fenga C},
	title = {Polyphenols: a route from bioavailability to bioactivity addressing potential health benefits to tackle human chronic diseases.},
	journal = {Arch Toxicol},
	year = {2023},
	abstract = {Chronic pathologies or non-communicable diseases (NCDs) include cardiovascular diseases, metabolic syndrome, neurological diseases, respiratory disorders and cancer. They are the leading global cause of human mortality and morbidity. Given their chronic nature, NCDs represent a growing social and economic burden, hence urging the need for ameliorating the existing preventive strategies, and for finding novel tackling therapies. NCDs are highly correlated with unhealthy lifestyle habits (such as high-fat and high-glucose diet, or sedentary life). In general, lifestyle approaches that might improve these habits, including dietary consumption of fresh vegetables, fruits and fibers, may contrast NCD symptoms and prolong life expectancy of affected people. Polyphenols (PPLs) are plant-derived molecules with demonstrated biological activities in humans, which include: radical scavenging and anti-oxidant activities, capability to modulate inflammation, as well as human enzymes, and even to bind nuclear receptors. For these reasons, PPLs are currently tested, both preclinically and clinically, as dietary adjuvants for the prevention and treatment of NCDs. In this review, we describe the human metabolism and bioactivity of PPLs. Also, we report what is currently known about PPLs interaction with gastro-intestinal enzymes and gut microbiota, which allows their biotransformation in many different metabolites with several biological functions. The systemic bioactivity of PPLs and the newly available PPL-delivery nanosystems are also described in detail. Finally, the up-to-date clinical studies assessing both safety and efficacy of dietary PPLs in individuals with different NCDs are hereby reported. Overall, the clinical results support the notion that PPLs from fruits, vegetables, but also from leaves or seeds extracts, are safe and show significant positive results in ameliorating symptoms and improving the whole quality of life of people with NCDs.},
	doi = {10.1007/s00204-022-03391-2},
	pmid = {36260104 [Indexed for MEDLINE]}
}

@ARTICLE{10.3390/antiox11081481,
	author = {Yang ZJ and Huang SY and Zhou DD and Xiong RG and Zhao CN and Fang AP and Zhang YJ and Li HB and Zhu HL},
	title = {Effects and Mechanisms of Curcumin for the Prevention and Management of Cancers: An Updated Review.},
	journal = {Antioxidants (Basel)},
	year = {2022},
	abstract = {Cancer is the leading cause of death in the world. Curcumin is the main ingredient in turmeric (Curcuma longa L.), and is widely used in the food industry. It shows anticancer properties on different types of cancers, and the underlying mechanisms of action include inhibiting cell proliferation, suppressing invasion and migration, promoting cell apoptosis, inducing autophagy, decreasing cancer stemness, increasing reactive oxygen species production, reducing inflammation, triggering ferroptosis, regulating gut microbiota, and adjuvant therapy. In addition, the anticancer action of curcumin is demonstrated in clinical trials. Moreover, the poor water solubility and low bioavailability of curcumin can be improved by a variety of nanotechnologies, which will promote its clinical effects. Furthermore, although curcumin shows some adverse effects, such as diarrhea and nausea, it is generally safe and tolerable. This paper is an updated review of the prevention and management of cancers by curcumin with a special attention to its mechanisms of action.},
	doi = {10.3390/antiox11081481},
	pmid = {36009200},
	note = {PMC9405286}
}
